export async function ingestChunk(
  dataSourceId: string,
  content: string,
  fileName: string,
): Promise<void> {
  try {
    // uploadDataSourceDocument handles chunking, embedding, and indexing.
    // Pass raw text (not a URL) and it creates a .txt document automatically.
    // Polls until processing is done — immediately queryable after this resolves.
    await mindstudio.uploadDataSourceDocument({
      dataSourceId,
      file: content,    // raw text string → creates a .txt document
      fileName,
    });
  } catch (err) {
    if (err instanceof MindStudioError) {
      console.error(`Ingestion failed [${err.code}] ${err.status}:`, err.message);
      throw err;
    }
    throw err;
  }
}

export async function retrieve(
  dataSourceId: string,
  query: string,
  maxResults = 5,
): Promise<string> {
  const { text } = await mindstudio.queryDataSource({
    dataSourceId,
    query,
    maxResults,
  });
  return text; // concatenated relevant chunks, ready to inject into a prompt
}
```

The only thing you lose is the raw vector — but if your goal is retrieval for RAG (not storing vectors for other downstream uses), you don't need it. `queryDataSource` returns the actual chunk text, which is what you'd inject into a prompt anyway.

**If your use case is specifically "I need to export, inspect, or compute over the raw float vectors" then the built-in stack won't work and you need the hybrid approach above.** Otherwise, skip the external embedding API entirely.

