+  // at line starts, blockquotes (>), and inline links `[x](y)`.
+  const docMatches =
+    (content.match(/^\s*(?:#{1,6}\s|[*+-]\s|>\s)/gm) || []).length +
+    (content.match(/\[[^\]]+\]\([^)]+\)/g) || []).length;
