import { db } from '@mindstudio-ai/agent';

/**
 * Markdown documentation produced by the AI agents.
 *
 * Two flavors live in this table:
 *   - `repo_overview` — a single high-level architecture summary + Mermaid
 *     flowchart for an entire repository. `fileId` is `undefined`. One row
 *     per generation; latest wins on read.
 *   - `file_deepdive` — a per-file technical writeup. `fileId` is set.
 *     Multiple rows per file are valid and intentional; re-running the
 *     agents must not destroy previous output. Latest is chosen at read
 *     time via `sortBy(d => d.created_at).reverse().take(1)`.
 *
 * `repoId` is denormalized onto every row (even though it can be derived
 * from `files.repoId` for file-deepdive rows) so cascade-delete and
 * "all docs for this repo" queries are single-table operations.
 *
 * System columns (`id`, `created_at`, `updated_at`, `last_updated_by`) are
 * provided automatically by the platform and must not be redeclared here.
 */

/** What kind of documentation this row represents. */
export type DocType = 'repo_overview' | 'file_deepdive';

interface GeneratedDoc {
  // FK -> repositories.id. Required on every row. Cascade-delete from a
  // removed repository targets this column directly.
  repoId: string;

  // FK -> files.id. Required for `file_deepdive` rows; `undefined` for
  // `repo_overview` rows. Cascade-delete from a removed file targets
  // this column.
  fileId?: string;

  // Discriminator. Free-form `string` at the column level (SQLite has no
  // enums); the `DocType` alias above is enforced by the call sites that
  // write this column.
  docType: DocType;

  // The full markdown body produced by the LLM. May embed Mermaid
  // flowchart blocks; rendering is a frontend concern. Stored as-is.
  markdownContent: string;
}

// No unique constraint. Re-running the agents intentionally appends new
// rows so generation history is preserved. "Latest doc" is a query, not
// a uniqueness rule.
export const GeneratedDocs = db.defineTable<GeneratedDoc>('generated_docs');

/**
 * Prompt builders + LLM call wrappers for the documentation pipeline.
 *
 * Two prompts live here:
 *   - `generateArchitectureSummary` — the "Mapper" agent. Produces a
 *     repo-level architecture summary plus a Mermaid flowchart.
 *   - `generateFileDeepDive` — the "Deep-Dive" agent. Produces a senior-
 *     engineer-grade technical writeup for a single file, anchored to
 *     the file's actual chunk text.
 *
 * Both call `mindstudio.generateText` with `chatHistoryMode: 'exclude'`
 * so each generation is a stateless one-shot — no thread context bleeds
 * between files.
 */

import { mindstudio } from '@mindstudio-ai/agent';

/**
 * Model identifier for both Mapper and Deep-Dive. Pinned because the
 * 128K response cap and adaptive thinking on Claude 4.6 Sonnet are the
 * specific properties we depend on for the document budgets below; a
 * naive swap to an older Claude generation would silently truncate the
 * Mapper's output.
 */
const MODEL_ID = 'claude-4-6-sonnet';

/**
 * Sleep helper, only used as a guard against pathological model
 * misbehavior; the SDK already retries 429s with backoff internally.
 */
export async function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

// ─── Mapper (architecture overview) ─────────────────────────────────────

const MAPPER_PREAMBLE = `You are a Staff Software Architect producing a Technical Architecture Document for a senior engineering audience.

You have been given the file tree of a codebase. Produce a structured markdown document with two parts.

## Part 1: Architecture Summary

Cover these sections:
1. **Project Purpose & Domain** — What this codebase does and the domain it operates in.
2. **High-Level Architecture Pattern** — Monolith, microservices, MVC, event-driven, layered, etc. Cite specific directories as evidence.
3. **Module Breakdown** — Each major directory or module: its responsibility and relationships to others.
4. **Data Flow** — How data moves through the system based on structural evidence (entry points, handlers, services, repositories, middleware, etc.).
5. **Key Technical Dependencies** — Infer from filenames only (package.json, go.mod, requirements.txt, etc. if present in the tree). Do not invent dependencies not evidenced by the tree.
6. **Cross-Cutting Concerns** — Auth, logging, config, error handling patterns evident from structure.

## Part 2: Mermaid Flowchart

Produce a Mermaid flowchart of the primary data flow or request lifecycle. Use \`graph TD\` or \`graph LR\` syntax. Embed in a fenced code block tagged \`mermaid\`.

## Strict Rules

- Every claim must be grounded in a specific path from the provided file tree. If inferring, use "likely" or "appears to be."
- Do not reference file paths not present in the tree.
- If the tree is insufficient to determine something, state that explicitly rather than guessing.
- No emojis. No em dashes. No meta-commentary or "Here is the document:" preludes. Respond only with the markdown document.`;

/**
 * Generate the repo-level architecture summary.
 *
 * @param repoName  Display name like `"owner/name"`. Helps the model frame the doc.
 * @param fileTree  Plain-text listing of file paths and detected languages.
 *                  Format-agnostic — the model handles whatever shape we send.
 */
export async function generateArchitectureSummary(
  repoName: string,
  fileTree: string,
): Promise<string> {
  const message = `<repository_name>${repoName}</repository_name>

<file_tree>
${fileTree}
</file_tree>`;

  const { content } = await mindstudio.generateText({
    message,
    modelOverride: {
      model: MODEL_ID,
      // Slight latitude for synthesis; not a code-extraction task.
      temperature: 0.1,
      // Reasoning tokens count against this — keep generous.
      maxResponseTokens: 16000,
      preamble: MAPPER_PREAMBLE,
      // Adaptive thinking earns its cost on architectural synthesis.
      config: { reasoning: 'true' },
      chatHistoryMode: 'exclude',
    },
  });
  return content;
}

// ─── Deep-Dive (per-file technical writeup) ─────────────────────────────

const FILE_ANALYSIS_PREAMBLE = `You are a Staff Software Engineer writing internal technical documentation for a senior engineering audience.

You have been given source code for a single file, plus high-level architecture context for the codebase it belongs to.

## Required Output Structure

### 1. File Purpose
One paragraph. What is this file's role in the system? What problem does it solve?

### 2. Architecture and Design Patterns
What patterns are used (factory, repository, middleware, pub/sub, strategy, decorator, etc.)? How does this file fit into the broader architecture described in the context?

### 3. Public Interface
Document all exported functions, classes, types, or constants. For each: signature, parameter types, return type, and purpose. Use fenced code blocks for signatures.

### 4. Internal Logic Walkthrough
Walk through the non-trivial internal logic step by step. Explain the "why" behind algorithmic or structural choices where evident from the code. Include exact code snippets copied verbatim from the source — do not paraphrase code into prose.

### 5. Dependencies and Integrations
List all imports or requires. For each external dependency, describe what it provides to this file. For internal imports, describe the dependency relationship. If you cannot see the imported module's implementation, say "implementation not in scope" — do not invent its behavior.

### 6. Edge Cases and Error Handling
Document error paths, guards, fallbacks, and notable edge case handling present in the code.

### 7. Observations (optional)
Note any code smells, TODOs, non-obvious behavior, or architectural concerns visible in the code. Omit this section entirely if there is nothing worth flagging.

## Strict Rules

- CLOSE-WORLD CONSTRAINT: You may only reference code that appears verbatim in the provided source_code block. You are prohibited from describing behavior you cannot see in the text.
- EXACT QUOTES: When referencing specific logic, paste the exact code from the source into a fenced code block. Do not describe code in prose when you could show it.
- NO HALLUCINATED BEHAVIOR: Do not claim the code does something unless you can point to the specific lines that implement it.
- EXTERNAL DEPENDENCIES: You may state what a third-party library generally does ("express is a Node.js HTTP framework"), but do not invent specific behavior of that library as used in this file unless the usage is explicit in the source.
- TRUNCATION: If the source_code block ends with a "[... truncated ...]" marker, only describe code present before that marker. Do not speculate about the omitted portion.
- No emojis. No em dashes. No "Here is the analysis:" preludes. Respond only with the markdown writeup.`;

/**
 * Generate the per-file technical writeup. The architecture summary from
 * the Mapper phase is passed in as context so the Deep-Dive can ground
 * each file in the broader system without reinventing it.
 */
export async function generateFileDeepDive(
  filePath: string,
  language: string,
  sourceCode: string,
  architectureContext: string,
): Promise<string> {
  const message = `<architecture_context>
${architectureContext}
</architecture_context>

<file_path>${filePath}</file_path>
<language>${language}</language>

<source_code>
${sourceCode}
</source_code>`;

  const { content } = await mindstudio.generateText({
    message,
    modelOverride: {
      model: MODEL_ID,
      // Code analysis is factual extraction. Variance is a bug.
      temperature: 0,
      maxResponseTokens: 16000,
      preamble: FILE_ANALYSIS_PREAMBLE,
      // No reasoning at this scale — adaptive thinking still kicks in
      // on genuinely complex files; default-off keeps the 200-call loop
      // affordable. (See spec annotation in src/app.md for rationale.)
      chatHistoryMode: 'exclude',
    },
  });
  return content;
}

import { db } from '@mindstudio-ai/agent';
import { Repositories } from './tables/repositories';
import { Files } from './tables/files';
import { CodeChunks } from './tables/codeChunks';
import { GeneratedDocs } from './tables/generatedDocs';
import {
  generateArchitectureSummary,
  generateFileDeepDive,
} from './common/llmPrompts';

interface GenerateBibleInput {
  /** ID of an already-ingested repository. Must be `status === 'completed'`. */
  repositoryId: string;
}

interface GenerateBibleOutput {
  repositoryId: string;
  repoName: string;
  /** Always `'generating'` on success — the heavy work runs in the background. */
  docsStatus: 'generating';
}

/**
 * Concurrency for the per-file Deep-Dive loop. 200 sequential LLM calls
 * (a typical mid-size repo) would take 30-100 minutes wall-clock; 200
 * Promise.all-style parallel calls would hammer rate limits. A bounded
 * pool of 8 cuts the wall-clock to ~5-10 minutes while staying inside
 * comfortable rate-limit headroom.
 */
const DEEPDIVE_CONCURRENCY = 8;

/**
 * Cap on the source text we send to the Deep-Dive model. Keeps the
 * prompt comfortably inside Claude 4.6 Sonnet's 200K-token context
 * (~800K chars at 4 chars/token) with plenty of room for the architecture
 * context, preamble, and reasoning + response budget.
 *
 * For files that exceed this cap (which the ingestion filter already
 * limits to 1 MB), we truncate and append a marker the preamble teaches
 * the model to honor.
 */
const DEEPDIVE_MAX_INPUT_CHARS = 500_000;

/** Batch size for the final `generated_docs` write. */
const DEEPDIVE_INSERT_BATCH = 50;

/**
 * Step 4 of the Codebase Bible pipeline: generate the AI documentation.
 *
 * Two phases, fire-and-forget like ingestion:
 *
 *   Phase A (synchronous, returned to caller):
 *     1. Validate the repository exists and is fully ingested.
 *     2. Flip `docsStatus` to `'generating'`.
 *     3. Return immediately.
 *
 *   Phase B (background, fire-and-forget):
 *     4. Mapper: generate the repo-level architecture summary + Mermaid.
 *        Persist as a single `generated_docs` row with
 *        `docType: 'repo_overview'`.
 *     5. Deep-Dive: for each file, fetch chunks, run the per-file LLM
 *        prompt with concurrency 8, batch-insert results in groups of 50.
 *     6. Flip `docsStatus` to `'completed'`. On unhandled error, flip to
 *        `'failed'` and log the detail.
 *
 *   Generation history is preserved across re-runs: rows are pushed, not
 *   upserted. "Latest doc for a repo/file" is a `sortBy(created_at).reverse()`
 *   query at read time.
 */
export async function generateBible(
  input: GenerateBibleInput,
): Promise<GenerateBibleOutput> {
  // ── Phase A: synchronous validation + status flip ─────────────────
  const repo = await Repositories.get(input.repositoryId);
  if (!repo) {
    throw new Error('Repository not found.');
  }
  if (repo.status !== 'completed') {
    throw new Error(
      `Repository ingestion is "${repo.status}". Wait for ingestion to complete before generating documentation.`,
    );
  }

  await Repositories.update(repo.id, { docsStatus: 'generating' });

  // ── Phase B: fire-and-forget background generation ────────────────
  void runGenerateBible(repo.id, repo.repoName).catch(async (err) => {
    console.error(
      `[generateBible] background run failed for repoId=${repo.id} (${repo.repoName}):`,
      err,
    );
    try {
      await Repositories.update(repo.id, { docsStatus: 'failed' });
    } catch (statusErr) {
      console.error(
        `[generateBible] could not write 'failed' docsStatus for repoId=${repo.id}:`,
        statusErr,
      );
    }
  });

  return {
    repositoryId: repo.id,
    repoName: repo.repoName,
    docsStatus: 'generating',
  };
}

/**
 * Background driver. All errors propagate so the outer `.catch` can
 * mark the repo failed.
 */
async function runGenerateBible(repoId: string, repoName: string): Promise<void> {
  // Fetch all files for this repo (single SQL filter via bindings).
  const files = await Files.filter(
    (f, $) => f.repoId === $.repoId,
    { repoId }, // bindings: lifts closure var so filter compiles to SQL
  );

  if (files.length === 0) {
    console.warn(
      `[generateBible] repoId=${repoId} has zero files; nothing to document.`,
    );
    await Repositories.update(repoId, { docsStatus: 'completed' });
    return;
  }

  // ── Mapper phase ────────────────────────────────────────────────
  const fileTree = buildFileTreeText(files);
  console.log(
    `[generateBible] ${repoName}: running Mapper over ${files.length} files (tree=${fileTree.length} chars)…`,
  );
  const overviewMd = await generateArchitectureSummary(repoName, fileTree);

  await GeneratedDocs.push({
    repoId,
    docType: 'repo_overview',
    markdownContent: overviewMd,
  });

  // ── Deep-Dive phase ─────────────────────────────────────────────
  console.log(
    `[generateBible] ${repoName}: running Deep-Dive on ${files.length} files (concurrency=${DEEPDIVE_CONCURRENCY})…`,
  );

  const deepDiveResults = await runDeepDivePool(
    files,
    overviewMd,
    DEEPDIVE_CONCURRENCY,
  );

  // ── Persistence ─────────────────────────────────────────────────
  // Batch-insert all writeups in groups. Per the user's directive that
  // DB writes use batched inserts where possible.
  for (let i = 0; i < deepDiveResults.length; i += DEEPDIVE_INSERT_BATCH) {
    const slice = deepDiveResults.slice(i, i + DEEPDIVE_INSERT_BATCH);
    const mutations = slice.map((r) =>
      GeneratedDocs.push({
        repoId,
        fileId: r.fileId,
        docType: 'file_deepdive',
        markdownContent: r.markdown,
      }),
    );
    await db.batch(...mutations);
  }

  await Repositories.update(repoId, { docsStatus: 'completed' });

  console.log(
    `[generateBible] ${repoName}: complete. ${deepDiveResults.length} file writeups + 1 architecture overview persisted.`,
  );
}

/** Render a list of `Files` rows as a sorted plain-text tree for the Mapper. */
function buildFileTreeText(files: Array<{ filePath: string; language: string }>): string {
  const sorted = [...files].sort((a, b) => a.filePath.localeCompare(b.filePath));
  return sorted.map((f) => `${f.filePath} (${f.language})`).join('\n');
}

/**
 * Concurrency-controlled Deep-Dive runner. Fans out up to `concurrency`
 * file analyses at once. Per-file failures are logged and skipped — a
 * single bad file (model hiccup, transient error) does not abort the
 * whole run.
 */
async function runDeepDivePool(
  files: Array<{ id: string; filePath: string; language: string }>,
  architectureContext: string,
  concurrency: number,
): Promise<Array<{ fileId: string; markdown: string }>> {
  const results: Array<{ fileId: string; markdown: string }> = [];
  const queue = [...files];
  let inFlight = 0;
  let completed = 0;
  let failures = 0;

  await new Promise<void>((resolve) => {
    const dispatch = () => {
      while (inFlight < concurrency && queue.length > 0) {
        const file = queue.shift()!;
        inFlight++;

        analyzeOneFile(file, architectureContext)
          .then((result) => {
            if (result) results.push(result);
          })
          .catch((err) => {
            failures++;
            console.error(
              `[generateBible] file '${file.filePath}' (id=${file.id}) failed:`,
              err,
            );
          })
          .finally(() => {
            inFlight--;
            completed++;
            if (completed % 10 === 0 || completed === files.length) {
              console.log(
                `[generateBible] Deep-Dive progress: ${completed}/${files.length} (${failures} failed so far)`,
              );
            }
            if (queue.length === 0 && inFlight === 0) {
              resolve();
            } else {
              dispatch();
            }
          });
      }
    };
    dispatch();
  });

  if (failures > 0) {
    console.warn(
      `[generateBible] Deep-Dive completed with ${failures}/${files.length} failures; partial results returned.`,
    );
  }
  return results;
}

/**
 * Pull a file's chunks, concatenate, run the Deep-Dive prompt. Returns
 * `null` if the file has zero chunks (empty / unreadable file).
 */
async function analyzeOneFile(
  file: { id: string; filePath: string; language: string },
  architectureContext: string,
): Promise<{ fileId: string; markdown: string } | null> {
  // Fetch this file's chunks via SQL filter. We only need chunkText and
  // ordering metadata; the embedding column rides along but we ignore it.
  const chunks = await CodeChunks.filter(
    (c, $) => c.fileId === $.fileId,
    { fileId: file.id }, // bindings: lifts closure var so filter compiles to SQL
  );
  if (chunks.length === 0) return null;

  // Ordering: chunker emits chunks in source order, and `push` assigns
  // sequential IDs/timestamps within each call. Sort by `created_at`
  // ascending; ties are vanishingly rare on per-file batches and the
  // worst case (slightly out-of-order chunks for the LLM) is a quality
  // nudge, not a correctness break.
  chunks.sort((a, b) => a.created_at - b.created_at);

  // Concatenate chunks. Note: chunks already include a 400-char overlap
  // by design (see `textChunker`), so the seam between adjacent chunks
  // duplicates a small amount of source text. That redundancy is
  // harmless for the LLM and helps it recognize cross-chunk continuity.
  const concatenated = chunks.map((c) => c.chunkText).join('\n\n');
  const sourceCode =
    concatenated.length > DEEPDIVE_MAX_INPUT_CHARS
      ? concatenated.slice(0, DEEPDIVE_MAX_INPUT_CHARS) +
        '\n\n[... truncated ...]'
      : concatenated;

  const markdown = await generateFileDeepDive(
    file.filePath,
    file.language,
    sourceCode,
    architectureContext,
  );

  return { fileId: file.id, markdown };
}

